      "background": "descrição detalhada com bokeh e profundidade",
      "paleta_cores": "3-4 tons, desaturated horror palette",
      "prompt_flux": "prompt COMPLETO montado com SETUP FIXO + todas as seções ANGLE/SUBJECT/LIGHT/FOREGROUND/MIDGROUND/BACKGROUND/COLOR",
      "prompt_movimento_wan": "movimento único em inglês, continuous motion throughout",
      "redux_strength": 0.65
    }
  ]
}`;

