  return `---\nCENA ${c.numero} (id: ${c.id})\nEmoção: ${c.emocao}\nTipo: ${c.tipo_cena}\nPersonagem presente: ${c.personagem_presente}\nPerspectiva: ${c.perspectiva}\nContinuidade: ${c.continuidade}\nTransição: ${c.transicao_entrada}\nNarração: "${c.narracao}"\nVisual: ${c.visual}\nMovimento: ${c.movimento}`;
